mapper.select:
SELECT COUNT(*) AS CNT
  FROM esg.tb_hr_menu_favorites
 WHERE comp_id = #{compId}
   AND hr_id = #{hrId}

SELECT COUNT(*) AS CNT
  FROM esg.tb_hr_menu_favorites
 WHERE menu_id = #{menuId}
   AND comp_id = #{compId}
   AND hr_id = #{hrId}

SELECT  coalesce(MAX(menu_odr), 0) + 1
  FROM esg.tb_hr_menu_favorites
 WHERE menu_id like 'F%'
   AND comp_id = #{compId}
   and hr_id = #{hrId}

mapper.insert:
SELECT #{faveId} AS faveId
WITH current_date_info AS ( SELECT TO_CHAR(CURRENT_DATE, 'YYYYMMDD') AS today, COALESCE(MAX(SUBSTRING(fave_id, 9, 4)::INTEGER), 0) AS max_sequence FROM esg.tb_hr_menu_favorites WHERE SUBSTRING(fave_id, 1, 8) = TO_CHAR(CURRENT_DATE, 'YYYYMMDD') ) SELECT today || CASE WHEN max_sequence = 0 THEN '0001' ELSE CASE WHEN max_sequence < 9999 THEN LPAD((max_sequence + 1)::TEXT, 4, '0') ELSE '0001' END END AS faveId FROM current_date_info;
INSERT INTO esg.tb_hr_menu_favorites ( menu_id, menu_nm, menu_odr, up_menu_id, use_yn, comp_id, hr_id, fave_id, new_yn ) VALUES ( #{menuId}, #{menuNm}, #{menuOdr}, #{upMenuId}, #{useYn}, #{compId}, #{hrId}, #{faveId}, #{newYn} ) ON CONFLICT (menu_id, comp_id, hr_id) DO UPDATE SET menu_nm = COALESCE(EXCLUDED.menu_nm, esg.tb_hr_menu_favorites.menu_nm), menu_odr = EXCLUDED.menu_odr, up_menu_id = COALESCE(EXCLUDED.up_menu_id, esg.tb_hr_menu_favorites.up_menu_id)

mapper.update:
UPDATE esg.tb_hr_menu_favorites
   SET menu_nm = coalesce(#{menuNm}, menu_nm),
       menu_odr = #{menuOdr},
       new_yn = #{newYn},
       up_menu_id = coalesce(#{upMenuId}, up_menu_id)
 WHERE comp_id = #{compId}
   AND hr_id = #{hrId}
   AND menu_id = #{menuId}

mapper.delete:
DELETE from esg.tb_hr_menu_favorites
 WHERE comp_id = #{compId}
   AND hr_id = #{currentUserHrId}
   AND (menu_id = #{menuId} OR up_menu_id = #{menuId})

DELETE FROM esg.tb_hr_menu_favorites
WHERE comp_id = #{compId}
  AND hr_id = #{hrId}
